class ScoutStats{ScoutStats({required this.points,required this.rank,required this.predictionsCount,required this.successfulPredictions,required this.failedPredictions,required this.expiredPredictions,this.accuracy,required this.currentSuccessStreak,required this.bestSuccessStreak});final int points,predictionsCount,successfulPredictions,failedPredictions,expiredPredictions,currentSuccessStreak,bestSuccessStreak;final String rank;final double? accuracy;factory ScoutStats.fromJson(Map<String,Object?> j)=>ScoutStats(points:((j['points']??0)as num).toInt(),rank:(j['rank']??'OBSERVER').toString(),predictionsCount:((j['predictionsCount']??0)as num).toInt(),successfulPredictions:((j['successfulPredictions']??0)as num).toInt(),failedPredictions:((j['failedPredictions']??0)as num).toInt(),expiredPredictions:((j['expiredPredictions']??0)as num).toInt(),accuracy:(j['accuracy'] as num?)?.toDouble(),currentSuccessStreak:((j['currentSuccessStreak']??0)as num).toInt(),bestSuccessStreak:((j['bestSuccessStreak']??0)as num).toInt());}
