class UserProfile{UserProfile({required this.id,required this.nickname,required this.votesCount,required this.submittedMemesCount,required this.status,required this.scout,required this.achievements,this.createdAt});final String id,nickname,status;final int votesCount,submittedMemesCount;final String? createdAt;final ScoutStats scout;final List<Achievement> achievements;factory UserProfile.fromJson(Map<String,Object?> j)=>UserProfile(id:j['id'].toString(),nickname:j['nickname'].toString(),votesCount:(j['votesCount'] as num).toInt(),submittedMemesCount:(j['submittedMemesCount'] as num).toInt(),status:(j['rank']??j['status']??'OBSERVER').toString(),scout:ScoutStats.fromJson((j['scout'] as Map?)?.cast<String,Object?>()??{}),achievements:((j['achievements'] as List?)??[]).cast<Map<String,Object?>>().map(Achievement.fromJson).toList(),createdAt:j['createdAt']?.toString());}
class MemeItem{MemeItem({required this.id,required this.title,required this.imageUrl,required this.rating,this.wins=0,this.losses=0,this.position});final String id,title,imageUrl;final int rating;final int wins,losses;final int? position;factory MemeItem.fromJson(Map<String,Object?> j)=>MemeItem(id:(j['id']??j['memeId']).toString(),title:j['title'].toString(),imageUrl:(j['contentUrl']??j['imageUrl']??'').toString(),rating:((j['rating']??0) as num).toInt(),wins:((j['wins']??0)as num).toInt(),losses:((j['losses']??0)as num).toInt(),position:j['position']==null?null:(j['position']as num).toInt());}
