String statusLabel(String s)=>rankLabel(s);String rankLabel(String s)=>switch(s){'OBSERVER'=>'Наблюдатель','SCOUT'=>'Мемный скаут','TREND_HUNTER'=>'Охотник за трендами','MEME_ORACLE'=>'Мемный оракул','NEWBIE'=>'Новичок','MEME_LORD'=>'Мемный лорд',_=>s};String predictionStatusLabel(String s)=>switch(s){'PENDING'=>'Ожидают','SUCCESS'=>'Успешные','FAILED'=>'Неудачные','EXPIRED'=>'Истёкшие',_=>s};String periodCode(int i)=>['DAY','WEEK','ALL_TIME'][i];String? validateNickname(String v){final t=v.trim();if(t.length<3||t.length>30)return 'Ник должен быть от 3 до 30 символов';if(!RegExp(r'^[A-Za-zА-Яа-я0-9_ -]+$').hasMatch(t))return 'Используйте буквы, цифры, пробел, _ или -';return null;}

String accuracyLabel(double? v)=>v==null?'—':'${(v*100).round()}%';
